import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';

import Home from './pages/home/Home';
import Services from './pages/services/Services';
import Blogs from './pages/blogs/Blogs';
import About from './pages/about/About';
import Contactus from './pages/contactus/ContactUs';
import Quiz from './pages/quiz/Quiz';
import Booking from './pages/services/booking/Booking';
import SingleBlog from './pages/blogs/singleblog/SingleBlog';
import ThankYouMessage from './pages/thankyoumessage/ThankYouMessage';
import CookiesPolicy from './pages/policies/cookiespolicy/CookiesPolicy';
import PrivacyPolicy from './pages/policies/privacypolicy/PrivacyPolicy';
import LegalNotice from './pages/policies/legalnotice/LegalNotice';

const App = () => {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/services" element={<Services />} />
        <Route path="/blogs" element={<Blogs />} />
        <Route path="/about" element={<About />} />
        <Route path="/contactus" element={<Contactus />} />
        <Route path="/quiz" element={<Quiz />} />
        <Route path="/booking" element={<Booking />} />
        <Route path="/singleblog" element={<SingleBlog />} />
        <Route path="/thankyoumessage" element={<ThankYouMessage />} />
        <Route path="/cookiespolicy" element={<CookiesPolicy />} />
        <Route path="/privacypolicy" element={<PrivacyPolicy />} />
        <Route path="/legalnotice" element={<LegalNotice />} />
      </Routes>
    </Router>
  );
};

export default App;
